\displaystyle{\begin{aligned}
   {\frac{\frac{2}{r}}{12+\frac{2t}{5}}} 
      \amp = {\frac{\frac{2}{r}}{12+\frac{2t}{5}}} \cdot \frac{{5r}}{{5r}} \\
      \amp = \frac{ \frac{2}{r} \cdot 5 r}{(12+\frac{2 t}{5}) \cdot 5 r} \\
      \amp = \frac{2 \cdot 5}{12 \cdot 5 r + \frac{2 t}{5} \cdot 5 r} \\
      \amp = \frac{10}{60 r + 2 r t} \\
      \amp = \frac{10}{2 r (30 + t)} \\
      \amp = {\frac{5}{r\mathopen{}\left(t+30\right)}\hbox{ or }\frac{5}{rt+30r}}
\end{aligned}
    }
